SELECT exercise_test_date, comments
FROM exercise_tests
WHERE patient_id = 1;

SELECT heart_rate
FROM heart_rate_monitoring
WHERE patient_id = 0 AND hrm_date = '2022-01-04';

SELECT COUNT(exercise_test_id) AS test_count
FROM exercise_tests
WHERE patient_id = 0;

SELECT COUNT(*) AS heart_rate_monitoring_count
FROM heart_rate_monitoring
WHERE patient_id = 0;

SELECT COUNT(*) AS abnormality_count
FROM ecg_abnormalities
WHERE abnormality_type = 'Conduction disorder';

SELECT heart_rate 
FROM vital_signs 
WHERE patient_id = 1;

SELECT COUNT(DISTINCT patient_id) AS high_glucose_count
FROM laboratory_results
WHERE lab_test = 'Glucose' AND CAST(result AS REAL) > 110;

SELECT result
FROM laboratory_results
WHERE patient_id = 1 AND lab_test = 'Glucose';

SELECT MAX(heart_rate) AS max_heart_rate
FROM heart_rate_monitoring
WHERE patient_id = 1;
